import React, { useState } from 'react';
import { Button, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd, formatDate, formatNumber } from '../../../utils/formatters';
import { exportExcel, MONTH_OPTIONS, YEAR_OPTIONS } from '../../../utils/exportExcel';
import styles from '../../../styles/erpReportPage.module.css';

import type { B01Row } from '../../../services/analytics/models';
const B01DnPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());
  const [rows, setRows] = useState<B01Row[]>([]);
  const [loading, setLoading] = useState(false);
  React.useEffect(() => { let c=false; setLoading(true); const t=setTimeout(()=>{ analyticsService.getB01Dn({ month, year }).then(d=>{if(!c)setRows(d);}).catch(e=>{if(!c)dispatch(addToast({message:e?.message??'Lỗi',type:'error'}));}).finally(()=>{if(!c)setLoading(false);}); },0); return ()=>{c=true;clearTimeout(t);}; }, [month,year,dispatch]);
  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}><div className={styles.titleBlock}><h1 className={styles.title}>B01-DN</h1></div>
        <div className={styles.headerActions}><Select value={String(month)} onChange={e=>setMonth(Number(e.target.value))} options={MONTH_OPTIONS} size="small" /><Select value={String(year)} onChange={e=>setYear(Number(e.target.value))} options={YEAR_OPTIONS} size="small" />
          <Button variant="secondary" onClick={()=>exportExcel('/reports/financial/b01-dn/export-excel',{month,year},`B01-T${month}-${year}.xlsx`)}><i className="fas fa-file-excel" /> Xuất Excel</Button></div></div>
      <div className={styles.tableCard}>{loading?<div className={styles.loading}><i className="fas fa-spinner fa-spin" /></div>:<div className={styles.tableWrapper}><table className={styles.table}><thead><tr><th>Chỉ tiêu</th><th className={styles.colRight}>Nợ ĐK</th><th className={styles.colRight}>Có ĐK</th><th className={styles.colRight}>Nợ CK</th><th className={styles.colRight}>Có CK</th></tr></thead><tbody>{rows.map((r,i)=>(<tr key={i} className={r.isTotal?styles.rowTotal:undefined}><td>{r.code} — {r.name}</td><td className={styles.colRight}>{formatVnd(r.openingDebit)}</td><td className={styles.colRight}>{formatVnd(r.openingCredit)}</td><td className={styles.colRight}>{formatVnd(r.closingDebit)}</td><td className={styles.colRight}>{formatVnd(r.closingCredit)}</td></tr>))}</tbody></table></div>}</div>
    </div>
  );
};
export default B01DnPage;
